import anthropic, json

client = anthropic.Anthropic()

# A tool the observer can use mid-session to quickly check spec coverage
COVERAGE_CHECK_TOOL = {
    "name": "check_spec_coverage",
    "description": "Check which must-do items in the spec are not yet covered by a test case",
    "input_schema": {
        "type": "object",
        "required": ["covered", "uncovered", "coverage_pct", "priority_gap"],
        "properties": {
            "covered": {
                "type": "array",
                "items": {"type": "string"},
                "description": "must-do IDs that have at least one passing eval case"
            },
            "uncovered": {
                "type": "array",
                "items": {"type": "string"},
                "description": "must-do IDs with no eval case"
            },
            "coverage_pct": {"type": "number"},
            "priority_gap": {
                "type": "string",
                "description": "The highest-priority uncovered must-do item and why it matters"
            }
        }
    }
}

def check_spec_coverage(behaviour_spec, eval_suite):
    """
    Observer calls this mid-session to identify the next must-do item to cover.
    behaviour_spec: list of {id, type, statement, test_signal}
    eval_suite: list of {id, spec_item_id, input, expected_behaviour}
    """
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        tools=[COVERAGE_CHECK_TOOL],
        tool_choice={"type": "tool", "name": "check_spec_coverage"},
        messages=[{
            "role": "user",
            "content": (
                f"Check spec coverage.\n\n"
                f"Behaviour spec (must_do items only):\n"
                f"{json.dumps([s for s in behaviour_spec if s['type']=='must_do'], indent=2)}\n\n"
                f"Current eval suite:\n{json.dumps(eval_suite, indent=2)}\n\n"
                "Identify must_do items with no corresponding eval case. "
                "priority_gap: the most important uncovered item — the one whose failure "
                "in production would cause the most harm."
            )
        }]
    )
    for block in response.content:
        if block.type == "tool_use":
            return block.input
    raise RuntimeError("No tool use in response")

import anthropic, json, hashlib, subprocess

client = anthropic.Anthropic()

PROMPT_CHANGE_TOOL = {
    "name": "propose_prompt_change",
    "description": "Propose a targeted prompt change to fix a specific eval failure",
    "input_schema": {
        "type": "object",
        "required": ["target_spec_item", "diagnosis", "proposed_change",
                     "placement", "expected_effect"],
        "properties": {
            "target_spec_item": {"type": "string"},
            "diagnosis": {
                "type": "string",
                "description": "Why the current prompt is failing this spec item"
            },
            "proposed_change": {
                "type": "string",
                "description": "Exact text to add, modify, or remove in the system prompt"
            },
            "placement": {
                "enum": ["replace_existing", "insert_after_role",
                         "insert_before_output_format", "append"]
            },
            "expected_effect": {
                "type": "string",
                "description": "Which eval cases should now pass, and which must-not-do behaviours should remain absent"
            }
        }
    }
}

class PairingSession:
    def __init__(self, system_prompt_path, eval_runner_path, behaviour_spec):
        self.prompt_path = system_prompt_path
        self.eval_runner = eval_runner_path
        self.spec = behaviour_spec
        with open(system_prompt_path) as f:
            self.current_prompt = f.read()

    def run_evals(self):
        """Driver: run after every prompt change"""
        result = subprocess.run(
            ["python3", self.eval_runner, "--prompt", self.prompt_path],
            capture_output=True, text=True
        )
        return json.loads(result.stdout)

    def propose_change(self, failing_spec_item_id, eval_output):
        """
        Observer calls this when they see a pattern in the failures.
        Driver implements the proposed change.
        """
        failing_cases = [
            c for c in eval_output["cases"]
            if c["spec_item_id"] == failing_spec_item_id and not c["passed"]
        ]
        spec_item = next(
            s for s in self.spec if s["id"] == failing_spec_item_id
        )

        response = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            tools=[PROMPT_CHANGE_TOOL],
            tool_choice={"type": "tool", "name": "propose_prompt_change"},
            messages=[{
                "role": "user",
                "content": (
                    f"Propose a prompt change to fix failing spec item {failing_spec_item_id}.\n\n"
                    f"Spec item: {json.dumps(spec_item)}\n\n"
                    f"Current prompt (first 800 chars):\n{self.current_prompt[:800]}\n\n"
                    f"Failing cases (sample of 3):\n{json.dumps(failing_cases[:3], indent=2)}\n\n"
                    "Be surgical — change the minimum necessary. "
                    "Do not add constraints that might break must-not-do items."
                )
            }]
        )
        for block in response.content:
            if block.type == "tool_use":
                return block.input
        raise RuntimeError("No tool use in response")

    def commit_change(self, new_prompt_text, registry_path):
        """Driver: commit prompt change with hash update"""
        with open(self.prompt_path, "w") as f:
            f.write(new_prompt_text)
        self.current_prompt = new_prompt_text

        new_hash = hashlib.sha256(new_prompt_text.encode()).hexdigest()
        with open(registry_path) as f:
            registry = json.load(f)
        registry["current_hash"] = new_hash
        registry["previous_hash"] = registry.get("current_hash", "")
        with open(registry_path, "w") as f:
            json.dump(registry, f, indent=2)

        return new_hash

import anthropic, json

client = anthropic.Anthropic()

DEBUG_HYPOTHESIS_TOOL = {
    "name": "generate_debug_hypotheses",
    "description": "Generate hypotheses for why a Claude prompt produced an unexpected output",
    "input_schema": {
        "type": "object",
        "required": ["hypotheses", "recommended_test"],
        "properties": {
            "hypotheses": {
                "type": "array",
                "maxItems": 5,
                "items": {
                    "type": "object",
                    "required": ["id", "hypothesis", "test_input", "expected_if_correct"],
                    "properties": {
                        "id": {"type": "string"},
                        "hypothesis": {"type": "string"},
                        "test_input": {
                            "type": "string",
                            "description": "An input that would confirm or refute this hypothesis"
                        },
                        "expected_if_correct": {
                            "type": "string",
                            "description": "What output you would expect if this hypothesis is the root cause"
                        }
                    }
                }
            },
            "recommended_test": {
                "type": "string",
                "description": "Which hypothesis to test first and why"
            }
        }
    }
}

def debug_unexpected_output(system_prompt, user_input, actual_output, expected_output):
    """
    The observer proposes hypotheses while the driver prepares test inputs.
    This externalises the debugging process so both engineers share the same hypotheses.
    """
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=1024,
        tools=[DEBUG_HYPOTHESIS_TOOL],
        tool_choice={"type": "tool", "name": "generate_debug_hypotheses"},
        messages=[{
            "role": "user",
            "content": (
                f"Generate hypotheses for this unexpected model output.\n\n"
                f"System prompt (first 600 chars):\n{system_prompt[:600]}\n\n"
                f"User input: {user_input}\n"
                f"Expected output: {expected_output}\n"
                f"Actual output: {actual_output}\n\n"
                "Generate up to 5 distinct hypotheses. Each must be falsifiable — "
                "suggest a specific test input that would confirm or refute it. "
                "Start with prompt ambiguity hypotheses before capability-limit hypotheses."
            )
        }]
    )
    for block in response.content:
        if block.type == "tool_use":
            return block.input
    raise RuntimeError("No tool use in response")
